sql:
SELECT AVG(f.avg_aid_amount) AS average_aid_amount
FROM financial_aid f
WHERE f.percent_students_aid > 70;

SELECT unitid, enrollment_total, enrollment_trend
FROM enrollment
ORDER BY enrollment_total DESC;

SELECT enrollment_total, enrollment_trend
FROM enrollment
WHERE enrollment_total > 10000;

SELECT enrollment_total
FROM enrollment
WHERE unitid = 12345;

SELECT unitid, enrollment_total
FROM enrollment
ORDER BY enrollment_total DESC;

SELECT graduation_rate
FROM student_outcomes
WHERE unitid = 12345;

SELECT avg_aid_amount
FROM financial_aid
WHERE unitid = 12345;

external_knowledge:
- Funding types may include public, private, for-profit, and non-profit institutions; 
- Settings may include urban, suburban, and rural areas;
- Graduation rates are often used as an indicator of an institution's effectiveness in supporting students to complete their programs.
